import numpy as np
from qiskit.quantum_info import Statevector
obs = Statevector.from_label('10').data
true_idx = int(np.argmax(np.abs(obs)))
claims = {"C": 2, "D": 1, "A": 3, "B": 0}
evidence = {}
proven = []
for k, i in claims.items():
    m = (true_idx == i)
    evidence[k] = f"from_label('10').data has its 1 at index {true_idx}; option {k} claims index {i} -> match={m}"
    if m:
        proven.append(k)
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"index": true_idx, "data": [str(x) for x in obs]}})
